using UnityEngine;
using UnityEngine.Purchasing;

public class PlayerStats : MonoBehaviour
{
    [Header("Core Stats (Public)")]
    public int level = 1;

    public float maxHealth = 100f;
    public float currentHealth = 100f;

    public int softCurrency = 0;
    public int premiumCurrency = 0;

    [Header("Combat (Public)")]
    public float baseDamage = 10f;
    public float damageMultiplier = 1f;
    public float critChance01 = 0.1f;
    public float critMultiplier = 2f;

    [Header("Defense (Public)")]
    public float armor = 0f;
    public float damageReduction01 = 0f;

    [Header("Progression (Public)")]
    public int damageUpgradeLevel = 0;
    public int healthUpgradeLevel = 0;

    public void HealFull()
    {
        currentHealth = maxHealth;
    }

    public void Heal(float amount)
    {
        if (amount <= 0f) return;
        currentHealth = Mathf.Min(maxHealth, currentHealth + amount);
    }

    public void TakeDamage(float incomingDamage)
    {
        if (incomingDamage <= 0f) return;

        float dmg = DamageCalculator.CalculateIncomingDamage(incomingDamage, armor, damageReduction01);
        currentHealth = Mathf.Max(0f, currentHealth - dmg);
    }

    public float CalculateOutgoingDamage()
    {
        return DamageCalculator.CalculateOutgoingDamage(baseDamage, damageMultiplier, critChance01, critMultiplier);
    }

    public bool IsDead()
    {
        return currentHealth <= 0f;
    }
}

public static class DamageCalculator
{
    public static float CalculateOutgoingDamage(float baseDamage, float damageMultiplier, float critChance01, float critMultiplier)
    {
        float dmg = Mathf.Max(0f, baseDamage) * Mathf.Max(0f, damageMultiplier);
        float roll = Random.value;
        if (roll < Mathf.Clamp01(critChance01))
            dmg *= Mathf.Max(1f, critMultiplier);
        return dmg;
    }

    public static float CalculateIncomingDamage(float incomingDamage, float armor, float damageReduction01)
    {
        float dmg = Mathf.Max(0f, incomingDamage);

        float armorFactor = 100f / (100f + Mathf.Max(0f, armor));
        dmg *= armorFactor;

        dmg *= (1f - Mathf.Clamp01(damageReduction01));

        return Mathf.Max(0f, dmg);
    }
}

public enum CurrencyType
{
    Soft,
    Premium
}

[System.Serializable]
public class ShopItemDefinition
{
    public string id;
    public string displayName;

    public CurrencyType currencyType = CurrencyType.Soft;

    public int basePrice = 100;
    public float priceGrowth = 1.15f;
    public int maxPurchases = 0;

    public int purchases = 0;

    public int healthBonusPerPurchase = 0;
    public float damageMultiplierBonusPerPurchase = 0.05f;

    public bool IsMaxed()
    {
        return maxPurchases > 0 && purchases >= maxPurchases;
    }

    public int CurrentPrice()
    {
        return PriceCalculator.CalculateScaledPrice(basePrice, priceGrowth, purchases);
    }

    public bool CanPurchase()
    {
        return !IsMaxed() && CurrentPrice() > 0;
    }
}

public static class PriceCalculator
{
    public static int CalculateScaledPrice(int basePrice, float growth, int purchaseCount)
    {
        if (basePrice <= 0) return 0;
        float g = Mathf.Max(1f, growth);
        int n = Mathf.Max(0, purchaseCount);
        double price = basePrice * System.Math.Pow(g, n);
        if (price > int.MaxValue) return int.MaxValue;
        return Mathf.Max(1, (int)System.Math.Round(price));
    }
}

public class ShopManager : MonoBehaviour
{
    public PlayerStats player;
    public ShopItemDefinition[] items;

    public bool TryPurchase(string itemId)
    {
        if (player == null || items == null) return false;

        ShopItemDefinition item = FindItem(itemId);
        if (item == null) return false;
        if (!item.CanPurchase()) return false;

        int price = item.CurrentPrice();
        if (!HasCurrency(item.currencyType, price)) return false;

        SpendCurrency(item.currencyType, price);
        ApplyItemEffects(item);
        item.purchases++;

        return true;
    }

    public int GetPrice(string itemId)
    {
        ShopItemDefinition item = FindItem(itemId);
        if (item == null) return 0;
        return item.CurrentPrice();
    }

    public bool CanAfford(string itemId)
    {
        ShopItemDefinition item = FindItem(itemId);
        if (item == null) return false;
        int price = item.CurrentPrice();
        return HasCurrency(item.currencyType, price);
    }

    ShopItemDefinition FindItem(string id)
    {
        if (string.IsNullOrEmpty(id)) return null;
        for (int i = 0; i < items.Length; i++)
        {
            if (items[i] != null && items[i].id == id)
                return items[i];
        }
        return null;
    }

    bool HasCurrency(CurrencyType type, int amount)
    {
        if (amount <= 0) return true;
        switch (type)
        {
            case CurrencyType.Soft: return player.softCurrency >= amount;
            case CurrencyType.Premium: return player.premiumCurrency >= amount;
            default: return false;
        }
    }

    void SpendCurrency(CurrencyType type, int amount)
    {
        if (amount <= 0) return;
        switch (type)
        {
            case CurrencyType.Soft:
                player.softCurrency = Mathf.Max(0, player.softCurrency - amount);
                break;
            case CurrencyType.Premium:
                player.premiumCurrency = Mathf.Max(0, player.premiumCurrency - amount);
                break;
        }
    }

    void ApplyItemEffects(ShopItemDefinition item)
    {
        if (item.healthBonusPerPurchase != 0)
        {
            player.maxHealth += item.healthBonusPerPurchase;
            player.currentHealth += item.healthBonusPerPurchase;
            player.currentHealth = Mathf.Min(player.currentHealth, player.maxHealth);
            player.healthUpgradeLevel++;
        }

        if (item.damageMultiplierBonusPerPurchase != 0f)
        {
            player.damageMultiplier += item.damageMultiplierBonusPerPurchase;
            player.damageUpgradeLevel++;
        }
    }
}

