public class IAPManager : MonoBehaviour, IStoreListener
{
    public PlayerStats player;

    [Header("IAP Product IDs (Match Store)")]
    public string premiumSmallId = "premium_small";
    public string premiumMediumId = "premium_medium";
    public string premiumLargeId = "premium_large";

    [Header("Rewards")]
    public int premiumSmallAmount = 50;
    public int premiumMediumAmount = 120;
    public int premiumLargeAmount = 300;

    IStoreController controller;
    IExtensionProvider extensions;

    void Start()
    {
        InitializePurchasing();
    }

    public void InitializePurchasing()
    {
        if (controller != null) return;

        var builder = ConfigurationBuilder.Instance(StandardPurchasingModule.Instance());

        builder.AddProduct(premiumSmallId, ProductType.Consumable);
        builder.AddProduct(premiumMediumId, ProductType.Consumable);
        builder.AddProduct(premiumLargeId, ProductType.Consumable);

        UnityPurchasing.Initialize(this, builder);
    }

    public void BuySmall() => BuyProduct(premiumSmallId);
    public void BuyMedium() => BuyProduct(premiumMediumId);
    public void BuyLarge() => BuyProduct(premiumLargeId);

    void BuyProduct(string productId)
    {
        if (controller == null) return;
        Product product = controller.products.WithID(productId);
        if (product != null && product.availableToPurchase)
            controller.InitiatePurchase(product);
    }

    public void OnInitialized(IStoreController controller, IExtensionProvider extensions)
    {
        this.controller = controller;
        this.extensions = extensions;
    }

    public void OnInitializeFailed(InitializationFailureReason error) { }
    public void OnInitializeFailed(InitializationFailureReason error, string message) { }

    public PurchaseProcessingResult ProcessPurchase(PurchaseEventArgs args)
    {
        if (player == null) return PurchaseProcessingResult.Complete;

        string id = args.purchasedProduct.definition.id;

        if (id == premiumSmallId) player.premiumCurrency += premiumSmallAmount;
        else if (id == premiumMediumId) player.premiumCurrency += premiumMediumAmount;
        else if (id == premiumLargeId) player.premiumCurrency += premiumLargeAmount;

        return PurchaseProcessingResult.Complete;
    }

    public void OnPurchaseFailed(Product product, PurchaseFailureReason failureReason) { }
}